#include <stdio.h>
#include <pthread.h>

/* == EXEMPLE ===============================================
 * Barrière : synchroniser 2 threads pour un calcul en 2 phases
 * Phase 1 : chaque thread calcule sa partie
 * Barrière : attendre que tous aient fini phase 1
 * Phase 2 : chaque thread utilise le résultat global
 * ========================================================= */
pthread_barrier_t ex_barrier;
int partial[2] = {0, 0};

void *phase_worker(void *arg) {
    int id = *(int *)arg;
    partial[id] = (id + 1) * 10; /* phase 1 */
    pthread_barrier_wait(&ex_barrier);
    /* phase 2 : tous les partial[] sont remplis */
    int total = partial[0] + partial[1];
    printf("Thread %d voit total=%d\n", id, total);
    return NULL;
}

void example_barrier(void) {
    pthread_t t[2];
    int ids[2] = {0, 1};
    pthread_barrier_init(&ex_barrier, NULL, 2);
    for (int i = 0; i < 2; i++)
        pthread_create(&t[i], NULL, phase_worker, &ids[i]);
    for (int i = 0; i < 2; i++)
        pthread_join(t[i], NULL);
    pthread_barrier_destroy(&ex_barrier);
}

